// Arithmetic
let sum = 5 + 10;
let product = 4 * 3;

// Comparison
if x >= 10 { /* ... */ }

// Ranges
for i in 0..5 { } // exclusive: 0,1,2,3,4
for i in 0..=5 { } // inclusive: 0,1,2,3,4,5

// Error propagation
let val = some_function()?;

// References
let r = &x;       // immutable reference
let r = &mut x;    // mutable reference

#[derive(Debug, Clone, PartialEq, Eq, Hash)]
struct Point {
    x: i32,
    y: i32,
}

let p1 = Point { x: 1, y: 2 };
let p2 = p1.clone();
assert_eq!(p1, p2);

#[derive(Default, Debug)]
struct Config {
    width: u32,
    height: u32,
}

let c = Config::default();
println!("{c:?}"); // Config { width: 0, height: 0 }
